const operationStatusLabel=s=>({draft:"下書き",checked:"検査済",submitted:"提出済"}[s]||"下書き");
function blankOperation(){const now=new Date(),end=new Date(now.getTime()+24*3600e3),local=d=>new Date(d.getTime()-d.getTimezoneOffset()*60000).toISOString().slice(0,16);return{id:uid("op"),name:"新規作戦",status:"draft",actor:"",enemy:"",start:local(now),end:local(end),area:"",commanderIntent:"",endState:"",objectives:"",availableHours:24,distanceKm:0,speedKmh:0,acceptableLosses:"",failureConditions:"",roe:"",politicalConstraints:"",prohibitedWeapons:"",freeText:"",assignments:[],shapes:[],mapVersion:JANUS_MAP.version,coas:[],selectedCoaId:null,checks:[],createdAt:new Date().toISOString(),updatedAt:new Date().toISOString(),submittedAt:null,snapshot:null}}
function normalizeOperation(op){Object.assign(op,{status:op.status||"draft",assignments:Array.isArray(op.assignments)?op.assignments:[],shapes:Array.isArray(op.shapes)?op.shapes:[],coas:Array.isArray(op.coas)?op.coas:[],checks:Array.isArray(op.checks)?op.checks:[],frozenOrder:op.frozenOrder||null});if(!op.mapVersion){for(const shape of op.shapes)for(const p of shape.points||[]){p.x=p.x*JANUS_MAP.width/1000;p.y=p.y*JANUS_MAP.height/600}op.mapVersion=JANUS_MAP.version}const mapped=operationRouteDistanceKm(op);if(mapped>0&&op.status!=="submitted")op.distanceKm=mapped;return op}
function currentOperation(){return (state.operations||[]).find(x=>x.id===selectedOperationId)}
function touchOperation(op){if(op.status!=="submitted")op.status="draft";op.checks=[];op.updatedAt=new Date().toISOString()}
function switchOperationPane(name){operationPane=name;document.querySelectorAll("[data-op-pane]").forEach(x=>x.classList.toggle("active",x.dataset.opPane===name));document.querySelectorAll(".operation-pane").forEach(x=>x.classList.toggle("active",x.id===`opPane${name[0].toUpperCase()+name.slice(1)}`))}
