  const judgeCurrentA=$("judgePlanA").value,judgeCurrentB=$("judgePlanB").value,judgeOptions=`<option value="">選択</option>`+state.operations.map(x=>`<option value="${x.id}">${esc(x.name)}［${operationStatusLabel(x.status)}］</option>`).join("");$("judgePlanA").innerHTML=judgeOptions;$("judgePlanB").innerHTML=judgeOptions;if(state.operations.some(x=>x.id===judgeCurrentA))$("judgePlanA").value=judgeCurrentA;if(state.operations.some(x=>x.id===judgeCurrentB))$("judgePlanB").value=judgeCurrentB;
