function operationOrderHtml(op){if(op.status==="submitted"&&op.frozenOrder)return op.frozenOrder;const coa=selectedCoa(op),force=operationAggregate(op),checks=op.checks||[],routeDistance=operationRouteDistanceKm(op),equipment=Object.entries(force.equipment).sort((a,b)=>b[1]-a[1]),mission=`${op.actor||"作戦主体"}は、${op.start||"開始時刻未定"}から${op.area||"作戦地域"}において、${op.objectives||"設定された目的"}を実施し、${op.endState||"所望の最終状態"}を達成する。`;return`<article><h1>${esc(op.name)}</h1><p class="order-meta">JANUS 作戦計画書 · ${operationStatusLabel(op.status)} · 更新 ${esc(op.updatedAt||"")}</p><h2>1. 情勢</h2><p><strong>作戦地域：</strong>${esc(op.area||"未設定")}<br><strong>敵情：</strong>${esc(op.enemy||"未設定")}<br><strong>友軍状況：</strong>${esc(op.actor||"未設定")}／割当${op.assignments.length}部隊<br><strong>情報上の不確実性：</strong>${esc(op.freeText||"別途情報見積を参照")}</p><h2>2. 任務</h2><p>${esc(mission)}</p><h2>3. 実行</h2><h3>指揮官意図</h3><p>${esc(op.commanderIntent||"未設定")}</p><h3>採用行動方針</h3><p><strong>${esc(coa?.title||"未選択")}</strong><br>${esc(coa?.summary||"COAを生成・選択すること。")}</p>${coa?`<h3>フェーズ</h3><ol>${coa.phases.map(x=>`<li>${esc(x)}</li>`).join("")}</ol>`:""}<h3>部隊任務</h3><table><thead><tr><th>部隊</th><th>階梯</th><th>任務</th></tr></thead><tbody>${op.assignments.map(a=>{const u=unit(a.unitId);return`<tr><td>${esc(u?.name||a.unitId)}</td><td>${esc(u?echelon(u.echelonId).name:"不明")}</td><td>${esc(a.task)}</td></tr>`}).join("")||`<tr><td colspan="3">未割当</td></tr>`}</tbody></table><p><strong>撤退・中止条件：</strong>${esc(op.failureConditions||"未設定")}<br><strong>作戦終了条件：</strong>${esc(op.endState||"未設定")}<br><strong>ROE：</strong>${esc(op.roe||"未設定")}</p><h2>4. 兵站</h2><p>重複する親子割当を除外した集計戦力：人員 ${force.personnel.toLocaleString()}名。計画移動距離：${(routeDistance||Number(op.distanceKm)||0).toLocaleString()}km${routeDistance?"（作戦図から算出）":""}。許容損耗：${esc(op.acceptableLosses||"未設定")}。</p><table><thead><tr><th>区分</th><th>品目</th><th>数量</th></tr></thead><tbody>${equipment.slice(0,30).map(([id,q])=>{const c=catalogItem(id);return`<tr><td>${esc(c?.category||"不明")}</td><td>${esc(c?.name||id)}</td><td>${q.toLocaleString()}</td></tr>`}).join("")||`<tr><td colspan="3">装備なし</td></tr>`}</tbody></table><h2>5. 指揮・通信</h2><p>作戦主体：${esc(op.actor||"未設定")}。指揮系統はORBAT上の上級・下級関係に従う。通信途絶時の権限移譲、作戦コード、識別規則は実施前に追記すること。</p><h2>付属書A 使用データ一覧</h2><p>ORBAT部隊 ${op.assignments.length}件、参照兵器 ${equipment.length}件、作戦図形 ${op.shapes.length}件。地図換算は1小マス100km、太線10マス1,000km。${op.snapshot?`情報スナップショット：${esc(op.snapshot.createdAt)}`:"提出時にスナップショットを確定する。"}</p><h2>付属書B 前提条件・検査結果</h2><ul>${checks.map(c=>`<li>[${c.severity.toUpperCase()}] ${esc(c.message)}</li>`).join("")||"<li>未検査</li>"}</ul><p><strong>政治的制約：</strong>${esc(op.politicalConstraints||"未設定")}<br><strong>使用禁止兵器：</strong>${esc(op.prohibitedWeapons||"未設定")}</p></article>`}
function createOperationSnapshot(op){const assigned=rootOperationAssignments(op),units=assigned.flatMap(a=>{const u=unit(a.unitId);return u?[u,...descendants(u.id)]:[]}),uniqueUnits=[...new Map(units.map(u=>[u.id,u])).values()],catalogIds=new Set(uniqueUnits.flatMap(u=>(u.equipment||[]).map(a=>a.catalogId)));return{createdAt:new Date().toISOString(),projectMeta:clone(state.meta),operation:clone({...op,snapshot:null}),units:clone(uniqueUnits),catalog:clone(state.catalog.filter(x=>catalogIds.has(x.id))),echelons:clone(state.echelons),unitTypes:clone(state.unitTypes)}}
